import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  standalone: true,
  imports: [CommonModule],
  templateUrl: './marcar.component.html',
  styleUrl: './marcar.component.scss'
})
export class MarcarComponent {
  puntos: string[] = ['Apertura de sesión', 'Aprobación acta anterior', 'Ruegos y preguntas', 'Cierre'];
}
<section class="min-h-screen bg-slate-100 p-4">
  <div class="max-w-md mx-auto bg-white rounded-2xl p-5 shadow">
    <h1 class="text-2xl font-bold mb-4">Marcar</h1>
    <button class="w-full bg-emerald-600 text-white text-xl py-4 rounded-xl mb-4">Marcar asistencia</button>
    <ul class="space-y-2">
      @for (punto of puntos; track punto) {
        <li class="bg-slate-50 rounded p-3">{{ punto }}</li>
      }
    </ul>
  </div>
</section>
